example.code:
resource "aws_budgets_budget" "monthly_cost" {
  name         = "monthly-total-cost"
  budget_type  = "COST"
  limit_amount = "10000"
  limit_unit   = "USD"
  time_unit    = "MONTHLY"

  notification {
    comparison_operator        = "GREATER_THAN"
    threshold                  = 80
    threshold_type             = "PERCENTAGE"
    notification_type          = "FORECASTED"
    subscriber_email_addresses = ["finops@company.com"]
  }

  notification {
    comparison_operator        = "GREATER_THAN"
    threshold                  = 100
    threshold_type             = "PERCENTAGE"
    notification_type          = "ACTUAL"
    subscriber_email_addresses = ["finops@company.com", "cto@company.com"]
  }

  cost_filter {
    name   = "TagKeyValue"
    values = ["user:environment$prod"]
  }
}

resource "google_billing_budget" "monthly_budget" {
  billing_account = "000000-AAAAAA-BBBBBB"
  display_name    = "Monthly Production Budget"

  budget_filter {
    projects = ["projects/${var.project_id}"]
    labels = {
      environment = "prod"
    }
  }

  amount {
    specified_amount {
      currency_code = "USD"
      units         = "10000"
    }
  }

  threshold_rules {
    threshold_percent = 0.5
    spend_basis       = "FORECASTED_SPEND"
  }

  threshold_rules {
    threshold_percent = 0.9
    spend_basis       = "CURRENT_SPEND"
  }

  threshold_rules {
    threshold_percent = 1.0
    spend_basis       = "CURRENT_SPEND"
  }

  all_updates_rule {
    monitoring_notification_channels = [
      google_monitoring_notification_channel.finops.id
    ]
    pubsub_topic = google_pubsub_topic.budget_alerts.id
  }
}
